import java.util.*;

public class TrafficOptimizer {

    public static Map<String, List<String>> trafficOptimizer(Map<String, Map<String, Integer>> graph) {
        Map<String, List<String>> optimizedPaths = new HashMap<>();
        Map<String, Integer> distances = new HashMap<>();
        Map<String, String> previousNodes = new HashMap<>();
        PriorityQueue<String> queue = new PriorityQueue<>(Comparator.comparingInt(distances::get));

        // Initialize distances and queue
        for (String intersection : graph.keySet()) {
            distances.put(intersection, Integer.MAX_VALUE);
        }
        distances.put(graph.keySet().iterator().next(), 0); // Start from the first intersection
        queue.addAll(graph.keySet());

        // Dijkstra's algorithm to find the least congested paths
        while (!queue.isEmpty()) {
            String current = queue.poll();
            for (Map.Entry<String, Integer> neighborEntry : graph.get(current).entrySet()) {
                String neighbor = neighborEntry.getKey();
                int trafficDensity = neighborEntry.getValue();
                int newDistance = distances.get(current) + trafficDensity;
                if (newDistance < distances.get(neighbor)) {
                    distances.put(neighbor, newDistance);
                    previousNodes.put(neighbor, current);
                    queue.remove(neighbor);
                    queue.add(neighbor);
                }
            }
        }

        // Reconstruct paths
        for (String intersection : graph.keySet()) {
            List<String> path = new ArrayList<>();
            String current = intersection;
            while (current != null) {
                path.add(current);
                current = previousNodes.get(current);
            }
            Collections.reverse(path);
            optimizedPaths.put(intersection, path);
        }

        return optimizedPaths;
    }
}
