import java.util.*;

public class NetworkAnalyzer {
    public static List<Integer> analyzeNetworkConnectivity(Map<Integer, List<Integer>> graph) {
        List<Integer> criticalNodes = new ArrayList<>();
        if (graph == null || graph.isEmpty()) {
            return criticalNodes;
        }

        Set<Integer> nodes = graph.keySet();
        for (int node : nodes) {
            Map<Integer, List<Integer>> tempGraph = new HashMap<>();
            for (Map.Entry<Integer, List<Integer>> entry : graph.entrySet()) {
                tempGraph.put(entry.getKey(), new ArrayList<>(entry.getValue()));
            }

            tempGraph.remove(node);
            for (List<Integer> edges : tempGraph.values()) {
                edges.removeIf(edge -> edge == node);
            }

            if (isDisconnected(tempGraph)) {
                criticalNodes.add(node);
            }
        }
        return criticalNodes;
    }

    private static boolean isDisconnected(Map<Integer, List<Integer>> graph) {
        if (graph.isEmpty()) {
            return false;
        }

        Set<Integer> visited = new HashSet<>();
        Queue<Integer> queue = new LinkedList<>();
        int startNode = graph.keySet().iterator().next();
        queue.add(startNode);
        visited.add(startNode);

        while (!queue.isEmpty()) {
            int current = queue.poll();
            for (int neighbor : graph.getOrDefault(current, Collections.emptyList())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
            }
        }

        return visited.size() != graph.size();
    }
}
