public class LoginHistoryManager {
    private Map<String, List<JSONObject>> loginHistory;

    public LoginHistoryManager() {
        this.loginHistory = new HashMap<>();
    }

    public JSONObject processLoginHistory(JSONObject request) {
        String operation = request.getString("operation");
        JSONObject response = new JSONObject();

        try {
            switch (operation) {
                case "add":
                    String userId = request.getJSONObject("data").getString("userId");
                    JSONObject loginRecord = request.getJSONObject("data").getJSONObject("loginRecord");
                    addLoginRecord(userId, loginRecord);
                    response.put("status", "success");
                    response.put("message", "Login record added successfully");
                    break;
                case "retrieve":
                    String retrieveUserId = request.getJSONObject("data").getString("userId");
                    int limit = request.getJSONObject("data").optInt("limit", 10);
                    JSONArray recentLogins = getRecentLogins(retrieveUserId, limit);
                    response.put("status", "success");
                    response.put("data", recentLogins);
                    break;
                case "delete":
                    String deleteUserId = request.getJSONObject("data").getString("userId");
                    if (request.getJSONObject("data").has("timestamp")) {
                        long timestamp = request.getJSONObject("data").getLong("timestamp");
                        deleteLoginRecord(deleteUserId, timestamp);
                        response.put("status", "success");
                        response.put("message", "Login record deleted successfully");
                    } else {
                        deleteAllUserLogins(deleteUserId);
                        response.put("status", "success");
                        response.put("message", "All login records deleted successfully");
                    }
                    break;
                default:
                    response.put("status", "error");
                    response.put("message", "Invalid operation");
            }
        } catch (Exception e) {
            response.put("status", "error");
            response.put("message", e.getMessage());
        }

        return response;
    }

    private void addLoginRecord(String userId, JSONObject loginRecord) {
        loginHistory.computeIfAbsent(userId, k -> new ArrayList<>()).add(loginRecord);
    }

    private JSONArray getRecentLogins(String userId, int limit) {
        List<JSONObject> userLogins = loginHistory.getOrDefault(userId, new ArrayList<>());
        int endIndex = Math.max(0, userLogins.size() - limit);
        JSONArray recentLogins = new JSONArray();
        for (int i = userLogins.size() - 1; i >= endIndex; i--) {
            recentLogins.put(userLogins.get(i));
        }
        return recentLogins;
    }

    private void deleteLoginRecord(String userId, long timestamp) {
        List<JSONObject> userLogins = loginHistory.get(userId);
        if (userLogins != null) {
            userLogins.removeIf(record -> record.getLong("timestamp") == timestamp);
        }
    }

    private void deleteAllUserLogins(String userId) {
        loginHistory.remove(userId);
    }
}
