using namespace std;

struct TreeNode {
    string permission;
    vector<TreeNode*> children;
    TreeNode(string perm) : permission(perm) {}
};

class PermissionTree {
private:
    TreeNode* root;
    unordered_map<string, TreeNode*> permissionMap;

    TreeNode* findPermissionNode(const string& perm) {
        if (permissionMap.find(perm) != permissionMap.end()) {
            return permissionMap[perm];
        }
        return nullptr;
    }

public:
    PermissionTree() : root(nullptr) {}

    void addPermission(const string& parentPerm, const string& newPerm) {
        TreeNode* newNode = new TreeNode(newPerm);
        permissionMap[newPerm] = newNode;

        if (parentPerm.empty()) {
            if (root == nullptr) {
                root = newNode;
            } else {
                cerr << "Root already exists" << endl;
                delete newNode;
            }
        } else {
            TreeNode* parentNode = findPermissionNode(parentPerm);
            if (parentNode) {
                parentNode->children.push_back(newNode);
            } else {
                cerr << "Parent permission not found" << endl;
                delete newNode;
            }
        }
    }

    void updatePermission(const string& oldPerm, const string& newPerm) {
        TreeNode* node = findPermissionNode(oldPerm);
        if (node) {
            node->permission = newPerm;
            permissionMap.erase(oldPerm);
            permissionMap[newPerm] = node;
        } else {
            cerr << "Permission not found" << endl;
        }
    }

    void removePermission(const string& perm) {
        TreeNode* node = findPermissionNode(perm);
        if (node) {
            // Remove all children recursively
            for (TreeNode* child : node->children) {
                removePermission(child->permission);
            }
            permissionMap.erase(perm);
            delete node;
        } else {
            cerr << "Permission not found" << endl;
        }
    }
};

void managePermissions(PermissionTree& tree, const string& operation, const string& perm1, const string& perm2 = "") {
    if (operation == "ADD") {
        tree.addPermission(perm1, perm2);
    } else if (operation == "UPDATE") {
        tree.updatePermission(perm1, perm2);
    } else if (operation == "REMOVE") {
        tree.removePermission(perm1);
    } else {
        cerr << "Invalid operation" << endl;
    }
}
