    let mut result = matrix.clone();
    for op in operations {
        match op {
            "rotate" => {
                let rows = result.len();
                if rows == 0 {
                    continue;
                }
                let cols = result[0].len();
                let mut rotated = vec![vec![0; rows]; cols];
                for i in 0..rows {
                    for j in 0..cols {
                        rotated[j][rows - 1 - i] = result[i][j];
                    }
                }
                result = rotated;
            }
            "flip" => {
                for row in result.iter_mut() {
                    row.reverse();
                }
            }
            "invert" => {
                for row in result.iter_mut() {
                    for val in row.iter_mut() {
                        *val = if *val == 0 { 1 } else { 0 };
                    }
                }
            }
            _ => {}
        }
    }
    result
