use std::collections::HashMap;

#[derive(Debug, Clone)]
struct NetworkNode {
    id: String,
    config: HashMap<String, String>,
    children: Vec<NetworkNode>,
}

#[derive(Debug)]
enum NetworkAction {
    Add { id: String, parent_id: Option<String>, config: HashMap<String, String> },
    Update { id: String, config: HashMap<String, String> },
    Remove { id: String },
    Get { id: String },
}

fn manage_network_config(root: &mut NetworkNode, action: NetworkAction) -> Option<HashMap<String, String>> {
    match action {
        NetworkAction::Add { id, parent_id, config } => {
            let new_node = NetworkNode {
                id: id.clone(),
                config,
                children: Vec::new(),
            };
            if let Some(parent_id) = parent_id {
                if let Some(parent) = find_node_mut(root, &parent_id) {
                    parent.children.push(new_node);
                }
            } else {
                root.children.push(new_node);
            }
            None
        }
        NetworkAction::Update { id, config } => {
            if let Some(node) = find_node_mut(root, &id) {
                node.config = config;
            }
            None
        }
        NetworkAction::Remove { id } => {
            remove_node(root, &id);
            None
        }
        NetworkAction::Get { id } => {
            find_node(root, &id).map(|node| node.config.clone())
        }
    }
}

fn find_node_mut(node: &mut NetworkNode, id: &str) -> Option<&mut NetworkNode> {
    if node.id == id {
        return Some(node);
    }
    for child in &mut node.children {
        if let Some(found) = find_node_mut(child, id) {
            return Some(found);
        }
    }
    None
}

fn find_node(node: &NetworkNode, id: &str) -> Option<&NetworkNode> {
    if node.id == id {
        return Some(node);
    }
    for child in &node.children {
        if let Some(found) = find_node(child, id) {
            return Some(found);
        }
    }
    None
}

fn remove_node(node: &mut NetworkNode, id: &str) -> bool {
    if let Some(pos) = node.children.iter().position(|child| child.id == id) {
        node.children.remove(pos);
        return true;
    }
    for child in &mut node.children {
        if remove_node(child, id) {
            return true;
        }
    }
    false
}
