        int startNode = input.getInt("startNode");
        String graphType = input.getString("graphType");
        JSONObject graphData = input.getJSONObject("graphData");

        Map<Integer, List<Integer>> graph = new HashMap<>();
        for (String key : graphData.keySet()) {
            int node = Integer.parseInt(key);
            List<Integer> neighbors = new ArrayList<>();
            for (Object neighbor : graphData.getJSONArray(key).toList()) {
                neighbors.add((Integer) neighbor);
            }
            graph.put(node, neighbors);
        }

        switch (algorithm) {
            case "BFS":
                bfs(graph, startNode, graphType);
                break;
            case "DFS":
                dfs(graph, startNode, graphType);
                break;
            default:
                System.out.println("Unsupported algorithm: " + algorithm);
        }
    }

    private static void bfs(Map<Integer, List<Integer>> graph, int startNode, String graphType) {
        Queue<Integer> queue = new LinkedList<>();
        Set<Integer> visited = new HashSet<>();
        queue.add(startNode);
        visited.add(startNode);

        while (!queue.isEmpty()) {
            int node = queue.poll();
            System.out.print(node + " ");

            for (int neighbor : graph.getOrDefault(node, new ArrayList<>())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
            }
        }
        System.out.println();
    }

    private static void dfs(Map<Integer, List<Integer>> graph, int startNode, String graphType) {
        Stack<Integer> stack = new Stack<>();
        Set<Integer> visited = new HashSet<>();
        stack.push(startNode);
        visited.add(startNode);

        while (!stack.isEmpty()) {
            int node = stack.pop();
            System.out.print(node + " ");

            for (int neighbor : graph.getOrDefault(node, new ArrayList<>())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    stack.push(neighbor);
                }
            }
        }
        System.out.println();
    }
