import org.json.JSONObject;
import java.util.HashMap;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;

public class FileSystemSimulator {
    private Map<String, String> folderParentMap;
    private Map<String, List<String>> folderChildrenMap;

    public FileSystemSimulator() {
        folderParentMap = new HashMap<>();
        folderChildrenMap = new HashMap<>();
        // Initialize root folder
        folderParentMap.put("root", null);
        folderChildrenMap.put("root", new LinkedList<>());
    }

    public String fs_simulator(JSONObject input) {
        String action = input.getString("action");
        String folderName = input.getString("folderName");
        String response = "";

        switch (action) {
            case "add":
                String parentFolder = input.optString("parentFolder", "root");
                addFolder(folderName, parentFolder);
                response = "Folder '" + folderName + "' added under '" + parentFolder + "'";
                break;
            case "move":
                String newParent = input.getString("newParent");
                moveFolder(folderName, newParent);
                response = "Folder '" + folderName + "' moved to '" + newParent + "'";
                break;
            case "remove":
                removeFolder(folderName);
                response = "Folder '" + folderName + "' removed";
                break;
            case "fetchPath":
                response = getFolderPath(folderName);
                break;
            default:
                response = "Invalid action";
        }

        return response;
    }

    private void addFolder(String folderName, String parentFolder) {
        if (folderParentMap.containsKey(folderName)) {
            throw new IllegalArgumentException("Folder already exists");
        }
        if (!folderParentMap.containsKey(parentFolder)) {
            throw new IllegalArgumentException("Parent folder does not exist");
        }
        folderParentMap.put(folderName, parentFolder);
        folderChildrenMap.computeIfAbsent(parentFolder, k -> new LinkedList<>()).add(folderName);
        folderChildrenMap.put(folderName, new LinkedList<>());
    }

    private void moveFolder(String folderName, String newParent) {
        if (!folderParentMap.containsKey(folderName) || !folderParentMap.containsKey(newParent)) {
            throw new IllegalArgumentException("Folder or new parent does not exist");
        }
        String oldParent = folderParentMap.get(folderName);
        folderChildrenMap.get(oldParent).remove(folderName);
        folderParentMap.put(folderName, newParent);
        folderChildrenMap.get(newParent).add(folderName);
    }

    private void removeFolder(String folderName) {
        if (!folderParentMap.containsKey(folderName)) {
            throw new IllegalArgumentException("Folder does not exist");
        }
        String parent = folderParentMap.get(folderName);
        folderChildrenMap.get(parent).remove(folderName);
        // Recursively remove all children
        List<String> children = new LinkedList<>(folderChildrenMap.get(folderName));
        for (String child : children) {
            removeFolder(child);
        }
        folderParentMap.remove(folderName);
        folderChildrenMap.remove(folderName);
    }

    private String getFolderPath(String folderName) {
        if (!folderParentMap.containsKey(folderName)) {
            return "Folder does not exist";
        }
        LinkedList<String> path = new LinkedList<>();
        String current = folderName;
        while (current != null) {
            path.addFirst(current);
            current = folderParentMap.get(current);
        }
        return String.join("/", path);
    }
}
